import init,{decode_upf_to_rgba}from"./pkg/upf_wasm_decoder.min.js";let wasmInitialized=false;let wasmPromise=null;async function bootEngine(){if(!wasmInitialized){if(!wasmPromise){wasmPromise=init()}await wasmPromise;wasmInitialized=true}}class UpfImage extends HTMLElement{static get observedAttributes(){return["src"]}constructor(){super();this.attachShadow({mode:"open"});this.canvas=document.createElement("canvas");this.canvas.style.display="block";this.canvas.style.maxWidth="100%";this.canvas.style.height="auto";this.shadowRoot.appendChild(this.canvas)}attributeChangedCallback(name,oldValue,newValue){if(name==="src"&&oldValue!==newValue){this.render()}}async connectedCallback(){if(this.getAttribute("src")){this.render()}}async render(){const src=this.getAttribute("src");if(!src)return;try{await bootEngine();const response=await fetch(src);const buffer=await response.arrayBuffer();const compressedBytes=new Uint8Array(buffer);const headerView=new Uint32Array(buffer.slice(0,16));const trueWidth=headerView[0];const trueHeight=headerView[1];this.canvas.width=trueWidth;this.canvas.height=trueHeight;const rawRgbaArray=decode_upf_to_rgba(compressedBytes);const ctx=this.canvas.getContext("2d");const imageData=new ImageData(new Uint8ClampedArray(rawRgbaArray),trueWidth,trueHeight);ctx.putImageData(imageData,0,0)}catch(error){console.error(`UPF Engine Error rendering ${src}:`,error)}}}customElements.define("upf-img",UpfImage);